def build_toc(markdown):
    lines = markdown.splitlines()
    toc_lines = []
    seen = {}  # heading text -> count

    for line in lines:
        if line.startswith("## "):
            level = 2
            text = line[3:].strip()
        elif line.startswith("### "):
            level = 3
            text = line[4:].strip()
        else:
            continue

        # Create anchor (GitHub-style lowercase hyphen)
        anchor = text.lower().replace(" ", "-")

        # Handle duplicates: first occurrence has no suffix, others get -1, -2, etc.
        if text in seen:
            seen[text] += 1
            anchor = f"{anchor}-{seen[text]}"
        else:
            seen[text] = 0

        # Format line with appropriate indentation
        if level == 2:
            toc_lines.append(f"- [{text}](#{anchor})")
        else:  # level 3
            toc_lines.append(f"  - [{text}](#{anchor})")

    return "\n".join(toc_lines)
